var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"흐음, 이 정도면 잘 마무리된 것 같네.","JPN":"ふう、これで粗方片付いたかな。","ENG":"Hmm, I think I'm finished here.","TWN":"嗯，這樣就差不多結束了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어때, 다친 곳은 없어?","JPN":"大丈夫？　怪我はない？","ENG":"How about you? Are you hurt?","TWN":"你怎麼樣？有沒有哪裡受傷了？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……말도 안 돼.","JPN":"……マジかよ。","ENG":"...No way.","TWN":"……怎麼可能。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"순식간에 괴물들을 쓰러트렸어.","JPN":"あっという間に化け物を全部倒した。","ENG":"You instantly defeated those monsters.","TWN":"怪物瞬間就被打敗了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"당신, 정체가 뭐야? 무슨 초능력자라도 되는 거야?","JPN":"あなたは何者？　超能力者？","ENG":"Who– What are you? Do you have superpowers or something?","TWN":"你到底是誰？那是什麼超能力嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 글쎄?","JPN":"うーん、そうねえ？","ENG":"Hmm, take a guess.","TWN":"嗯，猜猜看？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"애초에 너나 나처럼, 머리에 동물 귀를 달고 다니는 사람이 정상이라고 생각해?","JPN":"そもそも、あなたや私みたいに頭に動物の耳が生えてる人が普通の人間だと思う？","ENG":"Do you think it's normal for people to have animal ears like you and me?","TWN":"我其實一開始也和你一樣，你覺得像我們這樣頭上長著獸耳的人正常嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 초능력자라는 말도 크게 보면 틀린 건 아니지만…….","JPN":"まあ、超能力者って表現もある意味では間違ってはないけど……","ENG":"Well, I guess having superpowers isn't technically wrong...","TWN":"唔，大體上來說，叫做超能力者也沒什麼問題……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국에서는 우리 같은 능력자를 <color=#ffd34c>카운터</color>라고 불러.","JPN":"管理局では私たちみたいな能力者を<color=#ffd34c>カウンター</color>と呼んでいる。","ENG":"The Administration calls people with abilities like us <color=#ffd34c>Counters</color>.","TWN":"但在管理局，像我們這樣的人被稱為<color=#ffd34c>制裁者</color>。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>워치</color>를 얻고, <color=#ffd34c>초능력</color>을 각성한 능력자라서 말이야.","JPN":"<color=#ffd34c>ウォッチ</color>を手に入れ、<color=#ffd34c>超能力</color>を覚醒させた能力者のことね。","ENG":"Because we're awakened with <color=#ffd34c>superpowers</color> after obtaining a <color=#ffd34c>Watch</color>.","TWN":"就是得到<color=#ffd34c>能量環</color>，覺醒了<color=#ffd34c>超能力</color>的人。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 워치라고?","JPN":"待て、ウォッチだと？","ENG":"Hold on, a Watch?","TWN":"等等，能量環？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 워치란 게…… 설마, 이 <color=#ffd34c>시계</color>를 말하는 거야?","JPN":"そのウォッチってまさか……この<color=#ffd34c>時計</color>のこと？","ENG":"When you say Watch... do you mean this <color=#ffd34c>watch</color>?","TWN":"你說的那個能量環……難道是這支<color=#ffd34c>手錶</color>嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나한테 이 빌어먹을 귀랑 꼬리가 생겨난 게 전부 이 시계 때문이라고?","JPN":"アタシにこのくそみたいな耳と尻尾が生えたのも、この時計のせいなのか？","ENG":"So I have these stupid ears and tail because of this watch?","TWN":"就是因為這支手錶，我才長了這個該死的耳朵和尾巴？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"호오, 눈치가 빠른데? 하지만 반은 맞고 반은 틀리다고 해야하나?","JPN":"へえ、察しがいいじゃない。でも、半分だけ正解って感じかな。","ENG":"Ho-oh, you catch on quick. But you're only half right.","TWN":"唔，你很聰明嘛？但你只說對了一半喔～"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"왜냐하면 카운터라고 해도 다 우리처럼 귀나 꼬리를 달고 다니지는 않거든.","JPN":"カウンターと言っても、皆が私たちみたいに耳と尻尾が生える訳じゃないのよね。","ENG":"That's because not all Counters have ears and a tail like us.","TWN":"因為不是所有的制裁者都像我們一樣長著耳朵和尾巴。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"오히려 그 반대에 가까워.","JPN":"むしろその逆で。","ENG":"It's actually closer to the opposite.","TWN":"事實上，情況剛好相反。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 귀와 꼬리는 네 안에 <color=#ffd34c>원래부터</color> 잠재된 <color=#ffd34c>환상종 인자</color>가 각성을 계기로 발현한 거야.","JPN":"その耳と尻尾はあなたの中に<color=#ffd34c>元々</color>あった<color=#ffd34c>幻想種因子</color>が覚醒をきっかけに発現したものなの。","ENG":"Those ears and tail are the awakening of the <color=#ffd34c>Bygone Factor</color> that was <color=#ffd34c>originally</color> latent in you.","TWN":"耳朵和尾巴，是你覺醒了<color=#ffd34c>從一開始就</color>潛伏在你體內的<color=#ffd34c>夢幻品種因子</color>，才有的外在表達。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"아쉽지만, 환자분의 귀와 꼬리에 대해서 현대 의학적으로 드릴 수 있는 조언이 없네요.","JPN":"残念ながら、現代の医学ではあなたの耳と尻尾について何も申し上げることができません。","ENG":"I'm sorry, but there is no modern medical advice I can give you regarding your ears and tail.","TWN":"很遺憾，我無法為你提供有關耳朵和尾巴的醫學建議。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"마치 원래부터 있었던 것처럼 세포 조직이 연결되어 있어요.","JPN":"まるでもともと存在していたかのように、細胞組織が繋がっています。","ENG":"It seems that they are connected at the cellular level, as if they were there this whole time.","TWN":"它就像你原有的一樣，細胞組織都是相連的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 말은…… 원래부터 내가 평범한 인간이 아니었다는 뜻이야?","JPN":"つまり……アタシは元々普通の人間じゃなかったてことなのか？","ENG":"That means... that I was never an ordinary human being?","TWN":"你是說……我從一開始就不是個普通的人類嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래, 어쩌면 그 모습이 네 본질에 근접한 모습이라고 할 수도 있지.","JPN":"そう、もっと具体的に言うなら、その姿こそあなたの本質に近い姿だと言えるわね。","ENG":"Yeah. You could say that your current image comes closer to your essence.","TWN":"是的，你現在這個樣子，才是你最原本的模樣。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"워치는 그저 그 가능성을 실현시켜주었을 뿐이고.","JPN":"ウォッチはその可能性を実現させる道具にすぎない。","ENG":"And the Watch simply makes that possibility into reality.","TWN":"能量環只是讓這種可能性成為現實。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"축하해~","JPN":"おめでとう～","ENG":"Congratulations!","TWN":"恭喜你～"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아무래도 너도 우리처럼 조상 중에 인간이 아닌 존재가 섞여 있었던 모양이네.","JPN":"どうやら私たちのようにあなたの先祖の中にも、人間じゃない存在がいたようね。","ENG":"Seems like you're also like us who have a non-human ancestor mixed in the family tree.","TWN":"看來你和我們一樣，祖先中也有非人類。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"우리라고?","JPN":"私たち？","ENG":"Us?","TWN":"我們？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼, 우리처럼 환상종인가 뭔가 하는 녀석들이 더 있다는 거야?","JPN":"じゃあ、あなたとアタシの他にも幻想種ってやつらがいるってことか？","ENG":"Then there are more of these \\"Bygones\\" like us?","TWN":"那麼，還有很多像我們這樣的夢幻品種存在？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"もちろんよ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"따지고 보면, 우린 다 같은 동포라고 할 수 있으니까.","JPN":"私たちは同胞って言えるわね。","ENG":"If you think about it, you can say that we're compatriots.","TWN":"算起來，我們都是同伴。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어때? 순순히 날 따라오면 네가 궁금해하는 것들을 알려줄 테니까.","JPN":"どう？　大人しく私についてきてくれたら、あなたの知りたいことについて教えてあげる。","ENG":"So? If you follow me, I'll answer some questions you're curious about.","TWN":"怎麼樣？如果你乖乖跟我走，你想知道什麼，我都會告訴你。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리에 관해서도……. 그리고 이 세계의 진실에 관해서도 말이야.","JPN":"私たちのこと、そして……この世界の真実についても。","ENG":"About us, and... also about the truth of this world.","TWN":"關於我們……和這個世界的真相。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"만약 순순히 따라가지 않는다면?","JPN":"大人しくついて行く気はない、と言ったら？","ENG":"And if I don't?","TWN":"如果我不跟你走，你要怎麼辦？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"글쎄? 환상종 인자를 각성해버린 널 이대로 내버려 둘 생각은 없어서 말이야.","JPN":"そうねえ、幻想種の因子を覚醒してしまったあなたをこのまま放っておくつもりはないんだよね。","ENG":"Who knows. Because I have no intention of leaving an awakened Bygone Factor alone like this.","TWN":"這個嘛？我不會放任覺醒了夢幻品種因子的同伴不管的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"제 발로 따라오지 않으면, 꽁꽁 얼려서 납치라도 해줄까?","JPN":"ついて来ないって言うなら……キンキンに凍らせて拉致するとか？","ENG":"Maybe if you're not willing to follow me, should I freeze and kidnap you?","TWN":"如果你不跟我走，那我就把你凍住後綁走？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"납치라고?","JPN":"拉致？","ENG":"Kidnap?","TWN":"你要綁架我？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장, 취향이 고약하잖아?","JPN":"くそ、趣味が悪いな。","ENG":"Gah, you're horrible.","TWN":"可惡，你的興趣還真糟糕。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그걸 이제 알았어?","JPN":"ふふ、今さら気づいた？","ENG":"Fu fuu, did you just find out?","TWN":"呵呵，你現在才知道？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 간택이랑 납치. 어느 쪽이 좋아? 길고양이?","JPN":"じゃあ選んでもらうね、野良猫。拉致されるのと、自分の足でついて来るの、どっちがいい？","ENG":"What's it gonna be? Do you choose to come along, or do I have to kidnap you, stray cat?","TWN":"那麼，邀請還是綁架，你喜歡哪個？流浪貓？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};